

import React from 'react'
import { Badge, Col, Form, Row } from 'react-bootstrap';
import { IoIosCloudUpload } from 'react-icons/io';

const page = () => {
  return (
    <div>
      <h3>Upload Appointment Date</h3>

      <Row>
        <Col md={6}>
          <Form.Group className="form-group upload-group">
            <Form.Label className="d-flex align-items-center">
              <IoIosCloudUpload className="form-icon" /> Date
            </Form.Label>
            <div className="custom-file-upload">
              <input
                type="date"
                name="date"
                id="date"
                // onChange={handleFileChange}
              />
              {/* <label htmlFor="date" className="file-label">
                <span>Date</span>
              </label> */}
              {/* {offer_lette && (
                <div className="file-preview">
                  <span>File selected</span>
                  <Badge bg="success">Ready to upload</Badge>
                </div>
              )} */}
            </div>
          </Form.Group>
        </Col>
        <Col md={6}>
          <Form.Group className="form-group upload-group">
            <Form.Label className="d-flex align-items-center">
              <IoIosCloudUpload className="form-icon" /> Offer Letter
            </Form.Label>
            <div className="custom-file-upload">
              <input
                type="file"
                name="offer_letter"
                id="offer_letter"
                className="file-input"
                // onChange={handleFileChange}
                accept="application/pdf, image/*"
              />
              <label htmlFor="offer_letter" className="file-label">
                <IoIosCloudUpload className="upload-icon" />
                <span>Choose File</span>
              </label>
              {/* {offer_lette && (
                <div className="file-preview">
                  <span>File selected</span>
                  <Badge bg="success">Ready to upload</Badge>
                </div>
              )} */}
            </div>
          </Form.Group>
        </Col>
      </Row>
    </div>
  );
}

export default page
